mapper.select:
SELECT id, report_code, dict_name, dict_code,
       item_value, item_label, sort
FROM tb_report_dict
WHERE report_code = #{reportCode}
  AND dict_code = #{dictCode}
ORDER BY sort ASC

SELECT dict_code, item_value, item_label
FROM tb_report_dict
WHERE report_code = #{reportCode}

mapper.delete:
DELETE FROM tb_report_dict
WHERE report_code = #{reportCode}
  AND dict_code = #{dictCode}
  AND item_value = #{itemValue}
